import React, { useEffect, useState } from "react";

function Dashboard() {
  const [enquiries, setEnquiries] = useState([]);

  useEffect(() => {
    fetch("http://localhost:5000/api/enquiry")
      .then((res) => res.json())
      .then((data) => setEnquiries(data))
      .catch(() => alert("Failed to load enquiries"));
  }, []);

  return (
    <div className="dashboard">
      <h2>Client Enquiries</h2>

      {enquiries.length === 0 ? (
        <p>No enquiries found</p>
      ) : (
        <table>
          <thead>
            <tr>
              <th>Name</th>
              <th>Phone</th>
              <th>Location</th>
              <th>Service</th>
              <th>Message</th>
              <th>Status</th>
            </tr>
          </thead>

          <tbody>
            {enquiries.map((e) => (
              <tr key={e._id}>
                <td>{e.name}</td>
                <td>{e.phone}</td>
                <td>{e.location}</td>
                <td>{e.service}</td>
                <td>{e.message}</td>
                <td>New</td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

export default Dashboard;
